  { id: 'customers', tab: 'Potential customers', title: 'Businesses that need what you build.', sub: 'Companies with demand in {p}\u2019s sector, ranked by fit.' },
  { id: 'partners', tab: 'Partners & mentors', title: 'Partners & mentors for your R&D.', sub: 'Research partners and mentors in {p}\u2019s sector, ranked by fit.' },
  { id: 'talent', tab: 'Talent', title: 'People who fit your team.', sub: 'Candidates in {p}\u2019s sector, ranked by fit.' },
];
const WHY_NOW = {
  investors: 'Actively deploying this quarter \u2014 and the Q1 R&D tax-credit window makes co-investment materially cheaper.',
  partners: 'Research and mentorship capacity is open this cycle \u2014 engaging now lines up with your next product milestone.',
  customers: 'Annual budgets are being set now; early conversations put you on the roadmap before procurement locks.',
  talent: 'Strong candidates in this space are exploring moves this quarter \u2014 reaching out early wins their attention.',
};

class Component extends DCLogic {
  state = {
    authed: false, authMode: 'login', authEmail: '', authPassword: '', authError: '',
    role: null, status: 'draft', showErrors: false, savedAt: 0,
    view: 'form', topK: 5, selCandidate: null, emailLang: 'vi', copied: false, intent: 'investors',
    form: { name: '', website: '', stage: '', geography: '', sectors: [], need: '', traction: '', consent: false },
  };

  genDraft(c, lang, intent) {
    const who = this.state.form.name || (this.state.role === 'investor' ? 'our fund' : 'our startup');
    const need = (this.state.form.need || '').trim();
    const sect = c.sectors.join(lang === 'vi' ? ' và ' : ' and ');
    const person = intent === 'talent';
    if (lang === 'vi') {
      const hi = person ? 'Kính gửi ' + c.name + ',' : 'Kính gửi anh/chị tại ' + c.name + ',';
      const ask = intent === 'talent' ? 'Chúng tôi nghĩ bạn rất phù hợp với đội ngũ của ' + who + '.' : intent === 'customers' ? 'Chúng tôi tin giải pháp của ' + who + ' có thể hỗ trợ nhu cầu của quý vị.' : intent === 'investors' ? 'Chúng tôi đang tìm nhà đầu tư đồng hành cho vòng gọi vốn.' : 'Chúng tôi mong tìm cơ hội hợp tác nghiên cứu và cố vấn cùng quý vị.';
      return 'Chủ đề: ' + who + ' × ' + c.name + '\n\n' + hi + '\n\nTôi liên hệ từ ' + who + '. ' + (need || 'Chúng tôi đang xây dựng giải pháp dữ liệu đất cho nông dân Việt Nam.') + '\n\n' + ask + ' Với trọng tâm ở lĩnh vực ' + sect + ', quý vị có thể sắp xếp một cuộc trao đổi ngắn trong hai tuần tới không?\n\nTrân trọng,\n' + who;
    }
    const hi = person ? 'Dear ' + c.name + ',' : 'Dear team at ' + c.name + ',';
    const ask = intent === 'talent' ? "We think you'd be a great fit for the team at " + who + '.' : intent === 'customers' ? 'I believe ' + who + " can help with your team's needs." : intent === 'investors' ? "We're looking for an investor to partner on our round." : "We'd love to explore a research and mentorship collaboration.";
    return 'Subject: ' + who + ' × ' + c.name + '\n\n' + hi + "\n\nI'm reaching out from " + who + '. ' + (need || 'We are building soil-intelligence tools for Vietnamese farmers.') + '\n\n' + ask + ' Given your focus on ' + sect + ', would you be open to a short call in the next two weeks?\n\nWarm regards,\n' + who;
  }

  copyDraft() {
    const c = this.state.selCandidate || DATASETS[this.state.intent][0];
    const t = this.genDraft(c, this.state.emailLang, this.state.intent);
    try { if (navigator.clipboard) navigator.clipboard.writeText(t); } catch (e) {}
    this.setState({ copied: true });
  }

  hexToRgba(hex, a) {
    let h = (hex || '#1f7a5c').replace('#', '');
    if (h.length === 3) h = h.split('').map((c) => c + c).join('');
    const n = parseInt(h, 16);
    return 'rgba(' + ((n >> 16) & 255) + ',' + ((n >> 8) & 255) + ',' + (n & 255) + ',' + a + ')';
  }

  setField(k, v) { this.setState((s) => ({ form: { ...s.form, [k]: v }, status: 'draft', savedAt: 0 })); }
  toggleSector(id) {
    this.setState((s) => {
      const has = s.form.sectors.includes(id);
      return { form: { ...s.form, sectors: has ? s.form.sectors.filter((x) => x !== id) : [...s.form.sectors, id] }, status: 'draft', savedAt: 0 };
    });
  }

  validity() {
    const f = this.state.form;
    return {
      name: f.name.trim().length > 1,
      website: /\./.test(f.website.trim()) && f.website.trim().length > 3,
      stage: !!f.stage,
      geography: f.geography.trim().length > 1,
      sectors: f.sectors.length > 0,
      need: f.need.trim().length > 2,
      consent: f.consent === true,
    };
  }

  doAuth() {
    if (!this.state.authEmail.trim() || !this.state.authPassword.trim()) {
      this.setState({ authError: 'Enter your email and password to continue.' });
      return;
    }
    this.setState({ authed: true, authError: '', role: this.state.role || (this.props.defaultRole === 'Investor' ? 'investor' : 'startup') });
  }
  logout() { this.setState({ authed: false, authPassword: '' }); }

  markReady() {
    const v = this.validity();
    if (Object.values(v).every(Boolean)) this.setState({ status: 'ready', showErrors: false, view: 'matches' });
    else this.setState({ showErrors: true });
  }
  saveDraft() { this.setState({ status: 'draft', savedAt: Date.now() }); }

  renderVals() {
    const s = this.state;
    const accent = this.props.accent || '#1f7a5c';
    const role = s.role || (this.props.defaultRole === 'Investor' ? 'investor' : 'startup');
    const isInvestor = role === 'investor';
    const v = this.validity();
    const se = s.showErrors;
    const allValid = Object.values(v).every(Boolean);

    const baseInput = { width: '100%', height: '46px', padding: '0 14px', border: '1px solid #ddd9cf', borderRadius: '11px', background: '#fbfaf7', color: '#1a1a17', transition: 'border .15s,box-shadow .15s' };
    const areaInput = { width: '100%', minHeight: '92px', padding: '12px 14px', border: '1px solid #ddd9cf', borderRadius: '11px', background: '#fbfaf7', color: '#1a1a17', lineHeight: 1.55, resize: 'vertical', transition: 'border .15s,box-shadow .15s' };
    const errBorder = { border: '1px solid #d98b78', background: '#fdf6f3' };
    const inp = (ok, area) => (se && !ok) ? { ...(area ? areaInput : baseInput), ...errBorder } : (area ? areaInput : baseInput);

    const chip = (on) => on
      ? { padding: '9px 14px', border: '1px solid ' + accent, borderRadius: '99px', background: this.hexToRgba(accent, 0.1), color: accent, fontSize: '13px', fontWeight: 600 }
      : { padding: '9px 14px', border: '1px solid #ddd9cf', borderRadius: '99px', background: '#fff', color: '#5f5e55', fontSize: '13px', fontWeight: 500 };

    const roleBtn = (on) => on
      ? { padding: '9px 20px', border: '0', borderRadius: '9px', background: accent, color: '#fff', fontSize: '13.5px', fontWeight: 600 }
      : { padding: '9px 20px', border: '0', borderRadius: '9px', background: 'transparent', color: '#6b6b62', fontSize: '13.5px', fontWeight: 600 };

    const ready = s.status === 'ready';
    const statusStyle = ready
      ? { display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '5px 11px', borderRadius: '99px', background: this.hexToRgba(accent, 0.12), color: accent, fontSize: '11.5px', fontWeight: 700, letterSpacing: '.04em', textTransform: 'uppercase' }
      : { display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '5px 11px', borderRadius: '99px', background: '#efece4', color: '#8a887f', fontSize: '11.5px', fontWeight: 700, letterSpacing: '.04em', textTransform: 'uppercase' };

    const missingMap = { name: isInvestor ? 'fund name' : 'startup name', website: 'website', stage: isInvestor ? 'stage focus' : 'stage', geography: 'geography', sectors: 'sectors', need: isInvestor ? 'collaboration need' : 'funding need', consent: 'consent' };
    const missing = Object.keys(v).filter((k) => !v[k]).map((k) => missingMap[k]);

    const view = s.view;
    const active = (s.intent === 'investors' && isInvestor) ? STARTUPS : (DATASETS[s.intent] || CANDIDATES);
    const sorted = active.slice().sort((a, b) => b.score - a.score);
    const shown = s.topK >= sorted.length ? sorted : sorted.slice(0, s.topK);
    const scoreBadge = { display: 'grid', placeItems: 'center', width: '52px', height: '52px', borderRadius: '13px', background: this.hexToRgba(accent, 0.1), color: accent, font: "600 19px 'Hanken Grotesk'" };
    const dotS = (col) => ({ width: '7px', height: '7px', borderRadius: '50%', background: col, flex: 'none' });
    const matchList = shown.map((c) => ({ rank: '#' + (sorted.indexOf(c) + 1), score: c.score, name: c.name, type: c.type, rationale: c.rationale, scoreStyle: scoreBadge, dotStyle: dotS(c.dot), people: c.people || [], hasPeople: !!(c.people && c.people.length), open: () => this.setState({ view: 'detail', selCandidate: c, copied: false }) }));
    const cand = s.selCandidate || sorted[0];
    const lang = s.emailLang;
    const kBtn = (on) => on ? { padding: '8px 14px', border: '0', borderRadius: '8px', background: accent, color: '#fff', fontSize: '12.5px', fontWeight: 600 } : { padding: '8px 14px', border: '0', borderRadius: '8px', background: 'transparent', color: '#6b6b62', fontSize: '12.5px', fontWeight: 600 };
    const langTab = (on) => on ? { padding: '7px 13px', border: '0', borderRadius: '7px', background: accent, color: '#fff', fontSize: '12.5px', fontWeight: 600 } : { padding: '7px 13px', border: '0', borderRadius: '7px', background: 'transparent', color: '#6b6b62', fontSize: '12.5px', fontWeight: 600 };
    const clamp = (n) => Math.max(0, Math.min(100, Math.round(n)));
    const bar = (val) => ({ display: 'block', height: '100%', width: clamp(val) + '%', background: accent });
    const breakdown = [
      { label: 'Sector fit', val: clamp(cand.score + 6), barStyle: bar(cand.score + 6) },
      { label: 'Stage fit', val: clamp(cand.score - 4), barStyle: bar(cand.score - 4) },
      { label: 'Geography', val: clamp(cand.score - 9), barStyle: bar(cand.score - 9) },
      { label: 'Thesis alignment', val: clamp(cand.score + 2), barStyle: bar(cand.score + 2) },
    ];
    const whyNowMap = {
      'Venture Capital': 'Actively deploying this quarter — and the Q1 R&D tax-credit window makes co-investment materially cheaper. Reaching out now lands ahead of the crowd.',
      'University': 'The licensable IP here is unclaimed today. A first mover captures it before other startups or corporates move in.',
      'Research': 'Talent and lab capacity are available this cycle; engagement set up now is ready when your next milestone lands.',
      'Corporation': 'The Q1 R&D tax credit is about to lift corporate research and pilot budgets — appetite for partnerships is rising.',
      'Government': 'New programs and grants open in Q1; early applicants shape the agenda and get first access.',
    };
    const whyNot = 'Higher-scoring partners above offer a closer sector or stage fit for your current raise — revisit this one as your profile evolves.';
    const facts = [
      (s.intent === 'talent' ? 'Role · ' : 'Type · ') + cand.type,
      'Focus · ' + cand.sectors.join(', '),
      'Fit score · ' + cand.score + '/100',
      (cand.sources.length || 'No') + ' public source' + (cand.sources.length === 1 ? '' : 's') + ' checked',
    ];
    const detail = {
      name: cand.name, type: cand.type, score: cand.score, rationale: cand.rationale, sectors: cand.sectors, sources: cand.sources,
      hasSources: cand.sources.length > 0, noSources: cand.sources.length === 0,
      hasDraft: !cand.draftError, draftError: !!cand.draftError,
      draft: cand.draftError ? '' : this.genDraft(cand, lang, s.intent),
      dotStyle: dotS(cand.dot),
      bigScoreStyle: { display: 'grid', placeItems: 'center', width: '84px', height: '84px', borderRadius: '20px', background: this.hexToRgba(accent, 0.1), color: accent, font: "500 34px 'Newsreader'" },
      breakdown, whyNow: WHY_NOW[s.intent] || WHY_NOW.partners, whyNot, facts,
      rank: '#' + (sorted.indexOf(cand) + 1), confidencePct: clamp(cand.score - 2) + '%',
    };

    const pname = s.form.name || (isInvestor ? 'your fund' : 'your startup');
    const invSwap = isInvestor;
    const metaCur = INTENTS.find((i) => i.id === s.intent) || INTENTS[0];
    const curTitle = (s.intent === 'investors' && invSwap) ? 'Startups that fit your thesis.' : metaCur.title;
    const curSub = ((s.intent === 'investors' && invSwap) ? 'Startups in {p}’s focus, ranked by fit.' : metaCur.sub).replace('{p}', pname);

    return {
      isForm: view === 'form', isMatches: view === 'matches', isDetail: view === 'detail',
      goForm: () => this.setState({ view: 'form' }),
      goMatches: () => this.setState({ view: 'matches' }),
      readyAction: ready ? () => this.setState({ view: 'matches' }) : () => this.markReady(),
