  await page.getByRole('button', { name: 'Agritech', exact: true }).click();
  await page.locator('textarea').first().fill('Looking for agritech deal flow at seed.');
  await page.locator('input[type=checkbox]').check();
  await page.getByRole('button', { name: 'Mark as Ready' }).click();
  await page.waitForTimeout(1500);

  const thesisTitle = await page.getByText('Startups that fit your thesis.').isVisible().catch(() => false);
  const startupTab = await page.getByRole('button', { name: 'Startup', exact: true }).isVisible().catch(() => false);
  const enfarm = await page.getByText('enfarm', { exact: true }).isVisible().catch(() => false);
  console.log('investor matches: thesis title:', thesisTitle, '| Startup tab:', startupTab, '| enfarm listed:', enfarm);
  await page.screenshot({ path: `${SHOTS}/13-investor-matches.png` });

  console.log('CONSOLE ERRORS:', errors.length ? errors : 'none');
  await browser.close();
})().catch((e) => { console.error('FAILED:', e.message); process.exit(1); });

