const { chromium } = require('playwright');
const SHOTS = '/tmp/claude-1000/-home-delus-Documents-code-hackathon-dqplus-hackathon-2026/0ce68937-9e8e-4e34-b91e-16a5fd64984d/scratchpad/shots';
const fs = require('fs');
fs.mkdirSync(SHOTS, { recursive: true });

(async () => {
  const browser = await chromium.launch();
  const page = await browser.newPage({ viewport: { width: 1280, height: 900 } });
  const errors = [];
  page.on('console', (m) => { if (m.type() === 'error') errors.push(m.text()); });
  page.on('pageerror', (e) => errors.push('PAGEERROR: ' + e.message));

  const shot = (n) => page.screenshot({ path: `${SHOTS}/${n}.png`, fullPage: false });
  const email = `founder${Date.now()}@startup.vn`;

  // 1. Auth gate
  await page.goto('http://localhost:5173');
  await page.waitForTimeout(1200);
  await shot('1-auth');

  // 2. Register flow
  await page.getByText('Create an account').click();
  await page.waitForTimeout(400);
  await page.getByPlaceholder('you@startup.vn').fill(email);
  await page.getByPlaceholder('Your password').fill('secret123');
  await shot('2-register');
  await page.getByRole('button', { name: 'Create account' }).click();
  await page.waitForTimeout(1500);
  await shot('3-form-empty');
  const onForm = await page.getByText('Tell the ecosystem who you are.').isVisible().catch(() => false);
  console.log('registered+form visible:', onForm, '| email:', email);

  // 3. Fill profile form
  await page.getByPlaceholder('e.g. enfarm').fill('enfarm');
  await page.getByPlaceholder('https://…').fill('https://enfarm.vn');
  await page.locator('select').selectOption('seed');
  await page.getByPlaceholder('e.g. Vietnam · Southeast Asia').fill('Vietnam · Mekong Delta');
  await page.getByRole('button', { name: 'Agritech', exact: true }).click();
  await page.getByRole('button', { name: 'Cleantech', exact: true }).click();
  await page.locator('textarea').first().fill('Raising $1.5M seed to scale soil-intelligence sensors to 5 provinces.');

  // Save draft first (tests POST /profiles)
  await page.getByRole('button', { name: 'Save draft' }).click();
  await page.waitForTimeout(1200);
  await shot('4-draft-saved');
  const draftSaved = await page.getByText('Draft saved.').isVisible().catch(() => false);
  console.log('draft saved helper visible:', draftSaved);

  // Try ready without consent -> expect error summary
  await page.getByRole('button', { name: 'Mark as Ready' }).click();
  await page.waitForTimeout(500);
  await shot('5-validation');
  const summary = await page.getByText(/still needed before Ready/).isVisible().catch(() => false);
  console.log('validation summary shown:', summary);

  // Consent then ready
  await page.locator('input[type=checkbox]').check();
  await page.getByRole('button', { name: 'Mark as Ready' }).click();
  await page.waitForTimeout(1500);
  await shot('6-matches');
  const matches = await page.getByText('Matches · reasoning-ranked').isVisible().catch(() => false);
  const touchstone = await page.getByText('Touchstone Partners').isVisible().catch(() => false);
  console.log('matches view:', matches, '| top match Touchstone:', touchstone);

  // Ready pill in header
  const ready = await page.getByText('● Ready').isVisible().catch(() => false);
  console.log('header Ready pill:', ready);

  // Intent tab: partners
  await page.getByRole('button', { name: 'Partners & mentors' }).click();
  await page.waitForTimeout(900);
  await shot('7-partners');

  // Top 10
  await page.getByRole('button', { name: 'Top 10' }).click();
  await page.waitForTimeout(400);

  // Back to investors, open detail
  await page.getByRole('button', { name: 'Investment Fund' }).click();
  await page.waitForTimeout(700);
  await page.getByText('Touchstone Partners').click();
  await page.waitForTimeout(1400);
  await shot('8-detail');
  const why = await page.getByText('Why this match').isVisible().catch(() => false);
  const draftVI = await page.getByText(/Kính gửi/).isVisible().catch(() => false);
  console.log('detail view:', why, '| VI draft:', draftVI);

  // Switch to English
  await page.getByRole('button', { name: 'English' }).click();
  await page.waitForTimeout(400);
  const draftEN = await page.getByText(/Dear team at Touchstone Partners/).isVisible().catch(() => false);
  console.log('EN draft:', draftEN);
  await shot('9-detail-en');

  // NIC draft error state
  await page.getByText('← All matches').click();
  await page.waitForTimeout(600);
  await page.getByRole('button', { name: 'All', exact: true }).click();
  await page.waitForTimeout(500);
  await page.getByText('NIC', { exact: true }).click();
  await page.waitForTimeout(900);
  const draftErr = await page.getByText("Draft couldn't be generated").isVisible().catch(() => false);
  console.log('NIC draft error card:', draftErr);
  await shot('10-nic-error');

  // Reload -> session + profile persistence
  await page.goto('http://localhost:5173');
  await page.waitForTimeout(1500);
  const persisted = await page.getByText('Tell the ecosystem who you are.').isVisible().catch(() => false);
  const nameVal = await page.getByPlaceholder('e.g. enfarm').inputValue().catch(() => '');
  console.log('session persisted (form view):', persisted, '| name refilled:', nameVal);
  await shot('11-reload');

  console.log('CONSOLE ERRORS:', errors.length ? errors : 'none');
  await browser.close();
})().catch((e) => { console.error('FAILED:', e.message); process.exit(1); });

